pub fn mybusinessqanda_locations_questions_answers_upsert_builder(
    client: &SimpleHttpClient,
    parent: &str,
    body: &UpsertAnswerRequest,
) -> Result<ClientRequestBuilder<SystemDnsResolver>, ApiError> {
    // Build URL
    let url = format!(
        "https://mybusinessqanda.googleapis.com/v1/locations/{}/questions/{}/answers:upsert",
        parent,
    );

    // Build request
    let builder = client
        .get(&url)
        .map_err(|e| ApiError::RequestBuildFailed(e.to_string()))?;

    builder
        .body_json(body)
        .map_err(|e| ApiError::RequestBuildFailed(e.to_string()))
}

/// GET v1/locations/{locationsId}/questions/{questionsId}/answers:upsert
/// Creates an answer or updates the existing answer written by the user for the specified question. A user can only create one answer per question.
///
/// Takes a `ClientRequestBuilder`, builds and executes the request.
/// For customization, use `mybusinessqanda_locations_questions_answers_upsert_builder()` then pass to this function.
///
/// # Arguments
///
/// * `builder` - ClientRequestBuilder from mybusinessqanda_locations_questions_answers_upsert_builder()
///
/// # Errors
///
/// Returns an error if the request cannot be built.

pub fn mybusinessqanda_locations_questions_answers_upsert_execute(
    builder: ClientRequestBuilder<SystemDnsResolver>,
) -> Result<
    impl StreamIterator<D = Result<ApiResponse<Answer>, ApiError>, P = ApiPending> + Send + 'static,
    ApiError,
> {
    // Get SendRequestTask from builder
    let task = builder
        .build_send_request()
        .map_err(|e| ApiError::RequestBuildFailed(e.to_string()))?
        .map_ready(|intro| match intro {
            RequestIntro::Success {
                stream,
                intro,
                headers,
                ..
            } => {
                let status_code: usize = intro.0.into();

                if status_code < 200 || status_code >= 300 {
                    // Capture body for error parsing
                    let body = body_reader::collect_string(stream);
                    // Try to parse as structured API error
                    if let Ok(error_body) = serde_json::from_str::<ApiErrorBody>(&body) {
                        return Err(ApiError::ApiError(error_body.error));
                    }
                    // Fall back to raw HTTP status error
                    return Err(ApiError::HttpStatus {
                        code: status_code as u16,
                        headers: headers.clone(),
                        body: Some(body),
                    });
                }

                let body = body_reader::collect_string(stream);
                let parsed: Answer = serde_json::from_str(&body)
                    .map_err(|e| ApiError::ParseFailed(e.to_string()))?;

                Ok(ApiResponse {
                    status: status_code as u16,
                    headers: headers.clone(),
                    body: parsed,
                })
            }
            RequestIntro::Failed(e) => Err(ApiError::RequestSendFailed(e.to_string())),
        })
        .map_pending(|_| ApiPending::Sending);

    // Convert TaskIterator to StreamIterator
    execute(task, None).map_err(|e| ApiError::RequestBuildFailed(e.to_string()))
}

